func TestShieldUse(t *testing.T) {
	const dex = 40
	dexMul := statbonus.DEXBonus[dex] // oracle-verified in the statbonus package

	baseRate := 20.0
	rate := baseRate * dexMul // plain rate, no bow/crit multiplier

	if got := ShieldUse(baseRate, dex, false, false, 0, int(rate)-1); got != ShieldSuccess {
		t.Errorf("roll just below rate = %v, want ShieldSuccess", got)
	}
	if got := ShieldUse(baseRate, dex, false, false, 0, int(rate)+1); got != ShieldFailed {
		t.Errorf("roll just above rate = %v, want ShieldFailed", got)
	}
	if got := ShieldUse(0, dex, false, false, 0, 0); got != ShieldFailed {
		t.Errorf("zero base rate = %v, want ShieldFailed", got)
	}
	if got := ShieldUse(baseRate, dex, false, false, 50, 10); got != ShieldPerfect {
		t.Errorf("roll under perfect-block rate = %v, want ShieldPerfect", got)
	}

	// Bow and crit each triple the rate; both together give x9.
	tripled := ShieldUse(baseRate, dex, true, false, 0, int(rate*3)-1)
	if tripled != ShieldSuccess {
		t.Errorf("bow: roll just under tripled rate = %v, want ShieldSuccess", tripled)
	}
}
